import{_ as r,o as a,c as p,a7 as o}from"./chunks/framework.BgApuQ2e.js";const n="/images/spacexs-big-fking-rocket-the-full-story/Call-1.jpg",e="/images/spacexs-big-fking-rocket-the-full-story/Call-2.png",s="/images/spacexs-big-fking-rocket-the-full-story/Call-3.png",l="/images/spacexs-big-fking-rocket-the-full-story/Call-4.png",i="/images/spacexs-big-fking-rocket-the-full-story/Call-5-1.png",c="/images/spacexs-big-fking-rocket-the-full-story/Venn3.png",g="/images/spacexs-big-fking-rocket-the-full-story/light-second.png",h="/images/spacexs-big-fking-rocket-the-full-story/BFR-1.jpg",f="/images/spacexs-big-fking-rocket-the-full-story/BFR-house.jpg",m="/images/spacexs-big-fking-rocket-the-full-story/BFR-field-2-1.jpg",b="/images/spacexs-big-fking-rocket-the-full-story/bfr-boston.png",u="/images/spacexs-big-fking-rocket-the-full-story/Rocket-lineup-1.png",w="/images/spacexs-big-fking-rocket-the-full-story/Rocket-lineup-2.png",k="/images/spacexs-big-fking-rocket-the-full-story/Rocket-breakdown-2.png",_="/images/spacexs-big-fking-rocket-the-full-story/Raptor.jpg",y="/images/spacexs-big-fking-rocket-the-full-story/42-Raptors.jpg",d="/images/spacexs-big-fking-rocket-the-full-story/rocket-cross-section.jpg",S="/images/spacexs-big-fking-rocket-the-full-story/Observatory_F_HD_3.1.png",x="/images/spacexs-big-fking-rocket-the-full-story/Air-bridge.jpg",F="/images/spacexs-big-fking-rocket-the-full-story/29937258946_8345b8ae6e_o.jpg",B="/images/spacexs-big-fking-rocket-the-full-story/29343821794_9e05bfd6d7_h.jpg",E="/images/spacexs-big-fking-rocket-the-full-story/29343822854_ec6f4ffad1_h.jpg",R="/images/spacexs-big-fking-rocket-the-full-story/29343824424_87236132a0_h.jpg",X="/images/spacexs-big-fking-rocket-the-full-story/diagram.png",j="/images/spacexs-big-fking-rocket-the-full-story/29343909374_f5a0c62478_h.jpg",T="/images/spacexs-big-fking-rocket-the-full-story/29343908684_4caef4cd2c_h.jpg",q="/images/spacexs-big-fking-rocket-the-full-story/29343905184_aa6202b3a4_k.jpg",C="/images/spacexs-big-fking-rocket-the-full-story/29343906874_abb7572f12_k.jpg",M="/images/spacexs-big-fking-rocket-the-full-story/PDF-Button.png",v="/images/spacexs-big-fking-rocket-the-full-story/pinit_fg_en_rect_gray_20.png",G=JSON.parse(`{"title":"SpaceX's Big Fucking Rocket – The Full Story","description":"","frontmatter":{"title":"SpaceX's Big Fucking Rocket – The Full Story","titleZh":"SpaceX 巨型火箭全揭秘","date":"2016-09-28T00:00:00.000Z","originalUrl":"https://waitbutwhy.com/2016/09/spacexs-big-fking-rocket-the-full-story.html","slug":"spacexs-big-fking-rocket-the-full-story"},"headers":[],"relativePath":"posts/spacexs-big-fking-rocket-the-full-story.md","filePath":"posts/spacexs-big-fking-rocket-the-full-story.md","lastUpdated":1782886257000}`),P={name:"posts/spacexs-big-fking-rocket-the-full-story.md"};function I(A,t,D,H,W,z){return a(),p("div",null,[...t[0]||(t[0]=[o('<h1 id="spacex-巨型火箭全揭秘-·-spacex-s-big-fucking-rocket-–-the-full-story" tabindex="-1">SpaceX 巨型火箭全揭秘 · SpaceX&#39;s Big Fucking Rocket – The Full Story <a class="header-anchor" href="#spacex-巨型火箭全揭秘-·-spacex-s-big-fucking-rocket-–-the-full-story" aria-label="Permalink to &quot;SpaceX 巨型火箭全揭秘 · SpaceX&#39;s Big Fucking Rocket – The Full Story&quot;">​</a></h1><blockquote><p>原文:<a href="https://waitbutwhy.com/2016/09/spacexs-big-fking-rocket-the-full-story.html" target="_blank" rel="noreferrer">https://waitbutwhy.com/2016/09/spacexs-big-fking-rocket-the-full-story.html</a> · 2016-09-28</p></blockquote><p><em>我们做了一份漂亮的 PDF 版本(有原版和分级版),方便打印和离线阅读。<a href="https://gum.co/wbw-bfr" target="_blank" rel="noreferrer">点这里购买。</a> (或者看看<a href="https://waitbutwhy.com/wp-content/uploads/2016/10/spacexs-big-fking-rocket-the-full-story-preview.pdf" target="_blank" rel="noreferrer">预览</a>。)</em></p><p>昨天,埃隆·马斯克 (Elon Musk) 登上了 2016 年国际宇航大会 (International Astronautical Congress) 的舞台,<a href="https://www.youtube.com/watch?v=H7Uyfqi_TE8" target="_blank" rel="noreferrer">首次公开了真正的细节</a>,介绍了他们正在造的那枚牛逼哄哄的大火箭。</p><p>几个月前,SpaceX 第一次宣布要在 9 月底开这场发布会时,我突然想到——我在他们那儿可能还享有一点特殊待遇,算是从 2015 年跟埃隆和他的公司合作时留下来的老本(那次合作产出了<a href="https://waitbutwhy.com/2015/05/elon-musk-the-worlds-raddest-man.html" target="_blank" rel="noreferrer">一个四部曲的深度博客系列</a>)。于是我联系他们,问能不能提前了解这枚牛逼大火箭的情况,然后写一篇文章。</p><p>他们说可以。</p><p>过了一小会儿,我就和埃隆通上了电话,聊这枚火箭、时间表,以及这一切背后的宏大计划。我们像往常一样开场。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Call-1.jpg" target="_blank" rel="noreferrer"><img src="'+n+'" alt="(on the phone) Tim: You&#39;re Elon Musk. Elon: I&#39;m Elon Musk."></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Call-2.png" target="_blank" rel="noreferrer"><img src="'+e+'" alt="Stick Tim and Stick Elon on the phone in silence"></a></p><p>然后我提起了火箭的事。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Call-3.png" target="_blank" rel="noreferrer"><img src="'+s+'" alt="Tim: The Mars rocket is big. Elon: Yes, it&#39;s quite big."></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Call-4.png" target="_blank" rel="noreferrer"><img src="'+l+'" alt="Tim: It&#39;s gonna take people to Mars. Elon: That&#39;s the plan."></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Call-5-1.png" target="_blank" rel="noreferrer"><img src="'+i+'" alt="Tim: I&#39;m gonna get to go because I&#39;m a special boy. Elon: (silence)"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Call-2.png" target="_blank" rel="noreferrer"><img src="'+e+'" alt="Stick Tim and Stick Elon on the phone in silence"></a></p><p>最终,我们进入了一场引人入胜的对话,聊起了 SpaceX 正在造的这台疯狂机器,以及接下来会发生什么。</p><p>好,在正式开始之前——</p><p>这篇文章只是「SpaceX 故事」的一部分——那是我们这个时代最精彩的故事之一——去年我花了三个月、写了 40000 字来讲这个故事。如果你真想搞明白这件事,而且还没读过那篇文章,建议你先从那儿开始。那<a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html" target="_blank" rel="noreferrer">篇文章</a>分三部分,共五页:</p><p><strong><a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html" target="_blank" rel="noreferrer">第一部分:人类与太空的故事</a></strong></p><p><strong><a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html/2" target="_blank" rel="noreferrer">第二部分:马斯克的使命</a></strong></p><p><strong>第三部分:如何殖民火星</strong>**<br> → <a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html/3" target="_blank" rel="noreferrer">阶段一:搞清楚怎么把东西送上太空</a>**<br><strong>→ <a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html/4" target="_blank" rel="noreferrer">阶段二:彻底革新太空旅行的成本</a></strong><br><strong>→ <a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html/5" target="_blank" rel="noreferrer">阶段三:殖民火星</a></strong></p><p>给那些已经读过原文想复习一下的人,或者只想听听那台超级大火箭然后继续过日子的人,这里是背景的快速回顾:</p><p><strong>背景</strong></p><p>要理解为什么这台超级大火箭很重要,你得先理解这句话:</p><p><em>SpaceX 正在尝试通过在火星上建立一个能自给自足、有一百万人口的文明,让人类成为多行星物种。</em></p><p>我们一部分一部分来看。</p><p><strong>为什么要让人类成为多行星物种?</strong></p><p>两个理由:</p><p><strong>1) 好玩、令人激动。</strong>(<a href="https://soundcloud.com/waitbutwhy/2-reasons-to-go-to-mars" target="_blank" rel="noreferrer">这是一段音频</a>,来自我去年采访 Elon 时的一段对话,他在里面阐述了这一点。)</p><p>**2) 把所有鸡蛋放在一个篮子里不是什么好主意。**现在我们全都在地球上,这意味着如果地球上出了什么可怕的事——不管是自然造成的还是我们自己的技术造成的——我们就完蛋了。这就好比你有一本珍贵的数码相册,却只存在一块并不太可靠的硬盘上。如果你处于这种情况,聪明的做法是把相册备份到第二块硬盘上。这就是这里的思路。Elon 管这叫「人类物种的人寿保险」。</p><p><strong>为什么是火星?</strong></p><p>金星是个混蛋,气温高到能熔化铅、大气压能把你压扁、还有让人受不了的狂风。</p><p>月球几乎没有自然资源,一天有 29 天那么长,而且没有大气层——白天挡不住太阳,晚上也保不住温度——所以白天和晚上都能要人命。水星情况一样。</p><p>木星、土星、天王星和海王星只是些假装是行星的巨大气体球。</p><p>木星和土星的某些卫星或许可以住人,但它们比火星更远、更冷、更黑,所以我们干嘛要去那儿。</p><p>冥王星更远、更冷、更黑。别再问我冥王星了。</p><p>剩下的就是火星了。火星并不好玩。如果把火星搬到地球上,那会是没人愿意去的地方。但跟前面那些选项比起来,它简直是梦中情地。冷,但没那么冷。有点暗,但没比地球暗多少。远,但没那么远。它的一天几乎跟我们一样长,这对我们来说很不错,对种地球植物也是天大的帮助。表面重力不算离谱地低也不算离谱地高(大概是地球的三分之一)。它有大把(冻着的)水和相当量的二氧化碳,这些东西对早期在那儿生活的尝试至关重要,对未来把这颗行星「地球化 (terraform)」成更适合人类居住的地方也极为有用。综合来看,我们能有火星这么好的选项,简直是走运——在大多数其他恒星系里,我们大概是没有的。</p><p><strong>为什么是 100 万人?</strong></p><p>因为 Elon 认为这大致就是让火星文明变得「自给自足」所需的人数——「自给自足」被 Elon 定义为:「即使来自地球的飞船永远不再来了,这个殖民地也不会最终消亡——这需要庞大的工业基础,而且是比在地球上要难得多才能建立起来的工业基础。」</p><p>换句话说,如果硬盘 #2 需要依赖硬盘 #1 才能继续工作,那你的相册其实并没真正备份,对吧?硬盘 #2 存在的全部意义,就是在硬盘 #1 永久崩溃时救场。</p><p>而地球这块硬盘可能因为很多刺激的理由「崩掉」——小行星撞我们、<a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">AI 干掉我们</a>、川普干掉我们、ISIS 搞出某种让人不安的生物武器,等等——Elon 还警告了一种没那么戏剧化的可能性:地球的飞船不再来,仅仅是因为地球文明失去了送它们过去的能力:</p><p><em>来自地球的飞船可能因为别的原因停下来——可能是第三次世界大战,可能是地球变成了一个宗教国家,可能是某种渐进式的衰退,地球文明就这么被自身的重量压垮。</em> <em>埃及人曾经能建金字塔,然后他们就忘了怎么建。然后他们又忘了怎么读象形文字,直到罗塞塔石碑的出现。罗马也是——他们有室内水管,有先进的引水渠,然后这一切就散架了。中国曾经有全世界最大的帆船舰队,他们的船一路航行到非洲,然后来了个疯皇帝,觉得这不好,把船全烧了。所以你根本不知道会发生什么。要跨过的关键门槛,就是让一切自给自足所需的人数和货物吨数。那大概是 100 万人左右,货物大概是 1000 万到 1 亿吨。</em></p><p>换句话说,别在这事儿上磨蹭了。</p><p><strong>好,可你到底怎么把 100 万人送上火星?</strong></p><p>你得让下面这块绿色的部分真的存在:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Venn3.png" target="_blank" rel="noreferrer"><img src="'+c+'" alt="Blue circle: People who can afford to go to Mars. Yellow circle: People who want to go to Mars. Green intersection: At least a million people"></a></p><p>其实挺简单的。如果地球上能有 100 万人既<em>想</em>去火星,又<em>付得起</em>去火星的钱,那火星上就会有 100 万人。</p><p>不幸的是,现在黄色的圈很小,蓝色的圈根本不存在。</p><p>马斯克 (Elon) 觉得——我某种程度上也这么认为——只要蓝圈能足够大,黄圈自己就会长起来。如果火星既负担得起,又安全,还能保证你回得来,那很多人都会想去。</p><p>难的是蓝圈。问题在这儿:</p><p>上一次美国国会问 NASA 的时候,派 5 人机组去火星的成本是 500 亿美元。人均 100 亿。马斯克认为,要让蓝圈变得足够大,人均成本得降到 50 万美元。也就是当前成本的 1/20000。</p><p>1/20000。</p><p>这就好比看着汽车行业说:「现在一辆新本田大概要 2 万美元。要让这个行业成立,我们得把新车的成本降到 1 美元。」</p><p>那到底该怎么办?</p><p>问题就在这儿:</p><p>想象一下,如果飞机是这么运作的:起飞、飞到目的地,但不着陆,所有乘客都跳伞降到地面,然后飞机通过一头栽进海里、爆炸的方式「着陆」。也就是说每架飞机只飞一次,想要有下一趟航班,你就得再造一架新飞机。</p><p>一张机票会卖 150 万美元。</p><p>太空旅行现在之所以这么贵,主要就是因为我们「着陆」火箭的方式是让它们砸进海里(或者在大气层里烧成灰)。</p><p>马斯克创办 SpaceX 的时候就下定决心要解决这个问题。这是个艰巨任务,毕竟之前没人做到过——包括美国和俄罗斯这些花了几十亿去尝试的国家。但 SpaceX 一年又一年地啃这个难题,失败了一次又一次,终于在 2015 年底,他们搞定了:</p><p>然后又搞定了一次。又一次。又一次。现在他们已经是成功比失败多了。这是最近一次白天着陆的画面:</p><p>很快,一枚曾经飞过、着陆过、经过飞行验证的猎鹰 9 号 (Falcon 9) 将首次执行一次新任务,正式宣告 SpaceX 的火箭「可重复使用」。</p><p>用一枚二手火箭执飞任务,你只需要付推进剂(燃料和液氧)的钱,再加一点常规维护费。这一下就把太空旅行的价格砍到了原来的 1/100 甚至 1/1000。</p><p>也就是说,还剩下 19/20 到 199/200 的成本需要削减。其中一部分会在 SpaceX 一次运送 100 人以上(而不是 5 人——国会当年问 NASA 的就是这个数字)去火星时实现。剩下的部分则要靠几个简单的创新来搞定,比如在轨道上给飞船加注燃料(能把成本降低 5-10 倍),以及在火星上就地制造推进剂,这样你就不用把返程燃料一路背过去了(这又能把成本降低 5-10 倍)。这些东西后面会详细讲。</p><p>一下子,票价不仅能降到 50 万美元一张,甚至可能降得更低(Elon 认为最终可能降到每人 10 万美元以下)。你可能还没注意到,但 SpaceX 的这些创新,正在给太空旅行的成本带来一场彻底的革命——这种变化会打开一些我们今天难以想象的大门。而当这场革命走得足够远时,SpaceX 那个把 100 万人送上火星的愿景,真的——真的——认真地——有可能实现。</p><p>我们要去火星了。而这周,SpaceX 向我们展示了那个会带我们去火星的东西。</p><p><strong>这枚火箭</strong></p><p>“太震撼了。它每次都让我大脑爆炸,而我每周都能看到它。”</p><p>Elon 兴奋得不行。等你了解一下他正在造的这个巨大到不行的火箭,你就明白为什么了。</p><p>首先,让我们感受一下眼前的挑战。人们常说,太空很难搞。时至今日,只有几百个人进过太空,只有少数几个国家有能力把东西送上太空,而人类太空旅行的历史上到处散落着悲剧性的发射失败。要把一个超重、超脆弱、装满爆炸性液体的东西穿过大气层射上去,还得一点岔子都不出,这难度大得离谱。</p><p>但当我们说人类进入太空时,我们说的大多是人类进入近地轨道,也就是地面上方 100 到 1200 英里之间的那一层太空——通常他们只是往上飞 250 英里去国际空间站。人类唯一一次去得更远的时候,是 1960 年代那一小撮飞到月球的美国人,他们跑到了大约 25 万英里之外。</p><p>当地球和火星距离最近的时候,火星大约在 3400 万到 6000 万英里之外——比月球远大约 200 倍,比国际空间站远大约 20 万倍。</p><p>月球只有 1 光秒多一点的距离。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/light-second.png" target="_blank" rel="noreferrer"><img src="'+g+'" alt="distance diagram of Earth and the moon with a bar representing 1 light second that nearly reaches the moon"></a></p><p>而火星有 3 光<strong>分</strong>多。</p><p>火星很远。</p><p>Elon 喜欢把地球到火星的旅程比作横渡大西洋,他指出按这个比例,去月球就只相当于横渡英吉利海峡(去国际空间站则相当于走到离岸 117 英尺的一个码头)。沿用这个比喻,他说:「相比一个要飞出 1000 倍远距离的殖民运输系统,一枚为了飞到近地轨道甚至月球而造的火箭,基本上就像一艘沿海渔船。」</p><p>除此之外,把几个人或一颗卫星送上近地轨道也许还值得——但如果你要一路飞到火星,你会想带上<em>远远</em>不止这些。所以你必须把多得多的质量运到远得多的地方。把距离系数乘以载荷系数,Elon 解释说,一个火星运输系统「简直就是比目前全世界的发射系统能力强一百万倍。它必须如此。」</p><p>它还必须极其先进。Elon 说:「它不只是更大,还得更高效。谈到火箭时有一种错误的二分法,要么『小而复杂』,要么『大而笨』。人们常说『傻大个助推器』——那行不通。你需要的是又大又聪明的助推器。如果你想建一个火星殖民地,你别无选择——你必须造得又大又高效。」</p><p>所以你要做的就这些——造一枚比当今最强火箭强一百万倍、同时又高效又聪明、床上功夫还很好的火箭。</p><p>SpaceX 正在造它。请见识一下「大他妈的火箭 (Big Fucking Rocket)」。<a href="#footnote2-1-5715">1</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/BFR-1.jpg" target="_blank" rel="noreferrer"><img src="'+h+'" alt="spacex mars rocket"></a></p><p>从这张图里很难真正体会到它有多大。那我们加点参照物吧:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/BFR-house.jpg" target="_blank" rel="noreferrer"><img src="'+f+'" alt="spacex mars rocket with house and person drawn to scale"></a></p><p>或者这样呢?</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/BFR-field-2-1.jpg" target="_blank" rel="noreferrer"><img src="'+m+'" alt="spacex mars rocket shown over a football field for scale"></a></p><p>它对角线<em>勉强</em>能塞进一个橄榄球场,还差点就要顶到看台上去了。</p><p>还有这个:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/bfr-boston.png" target="_blank" rel="noreferrer"><img src="'+b+'" alt="spacex mars rocket in skyline for scale"></a></p><p>它就是一栋<em>摩天大楼</em>。或者用 Elon 的话说,「迄今为止最大的飞行物,遥遥领先。」</p><p>在昨天的发布会上,Elon 解释说,这不是关于它长什么样的初步草图,也不是艺术家的想象图——它就长这样。这就是他们正在造的东西。</p><p>不幸的是,SpaceX 在给这玩意儿起名字这件事上似乎正经历一场存在主义危机——一开始它叫「火星殖民运输船 (Mars Colonial Transporter)」,后来(因为它能飞到<a href="https://twitter.com/elonmusk/status/776939304140414976" target="_blank" rel="noreferrer">比火星远得多的地方</a>)被<a href="https://twitter.com/elonmusk/status/777325549442232320" target="_blank" rel="noreferrer">改名</a>为「行星际运输系统 (Interplanetary Transport System)」,再后来昨天的发布会上,Elon 说他们其实还没定下名字,但首次飞往火星的那艘特定飞船可能会叫「黄金之心 (Heart of Gold)」<a href="#footnote-1-5715">1</a>——所以没人知道该怎么叫它。</p><p>正因如此——在我听到其他说法之前——我会用我以前在一次采访里听 Elon 形容它的那个词来称呼它:大他妈的火箭 (Big Fucking Rocket, BFR)。</p><p>大他妈的火箭是真他妈的大。它高达 400 英尺,相当于一栋 40 层摩天大楼的高度。直径 40 英尺,一辆校车可以完全塞进它的底座之下。它的质量是巨型的<a href="http://www.astronautix.com/graphics/s/satvb.jpg" target="_blank" rel="noreferrer">土星五号 (Saturn V)</a>——阿波罗任务用的那款火箭,也是目前为止人类造过的最大火箭——的三倍多,推力也是它的三倍多。</p><p>下面是它和其他一堆火箭在体积上的对比:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Rocket-lineup-1.png" target="_blank" rel="noreferrer"><img src="'+u+'" alt="rocket-lineup"></a></p><p>如果按每枚火箭能送入轨道的有效载荷(也就是货物和/或人员)公斤数来比,差距就更夸张了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Rocket-lineup-2.png" target="_blank" rel="noreferrer"><img src="'+w+'" alt="rocket-lineup-2"></a></p><p>作为对比,SpaceX 那款屌炸天的<a href="http://www.spacex.com/falcon9" target="_blank" rel="noreferrer">猎鹰 9 号 (Falcon 9)</a> 火箭能把大约 4 吨的载荷送上火星,而<a href="http://www.spacex.com/falcon-heavy" target="_blank" rel="noreferrer">猎鹰重型 (Falcon Heavy)</a>——即将成为当今最强大的火箭——能把约 13 吨送上火星。Elon 相信 BFR 一开始就能把几<em>百</em>吨载荷送上火星,最终能达到 <em>1000</em> 吨。这个数据的荒谬程度——庞然大物猎鹰重型的载荷能力仅仅只有 BFR 最终火星载荷的 1% 出头——真的挺难消化的。</p><p>不过,先说清楚——我这一路称之为「大他妈的火箭」的东西,其实是两个部分:一艘大他妈的飞船,坐在一枚大他妈的助推器上面。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Rocket-breakdown-2.png" target="_blank" rel="noreferrer"><img src="'+k+'" alt="diagram of spacex mars rocket. spaceship: crew cabin, cargo cabin, liquid oxygen tank, methane fuel tank, 9 Raptor engines. booster: liquid oxygen tank, methane fuel tank, 42 Raptor engines"></a></p><p><strong>大他妈的助推器</strong></p><p>我们先从助推器 (booster) 说起。这个 25 层楼高的助推器——也就是 BFR 真正的火箭部分——被埃隆称作「相当野的一头猛兽」。它是有史以来最大的助推器——遥遥领先。物理尺寸上肯定是,但推力方面更是碾压。</p><p>在 SpaceX 那篇文章里,我<a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html/4" target="_blank" rel="noreferrer">讲过</a> Falcon 9 上那 9 台 <a href="http://www.spacex.com/news/2013/03/26/merlin-engines" target="_blank" rel="noreferrer">Merlin 发动机</a>,每一台的推力都足以把 40 辆汽车叠起来送上天——加起来,Falcon 9 这套发动机可以举起 360 辆车。而 Falcon Heavy 上的 27 台 Merlin 发动机,可以把 1000 多辆车叠起来推过云层。<a href="#footnote-2-5715">2</a></p><p>大他妈的助推器 (Big Fucking Booster) 用的是另一种发动机:猛禽 (Raptor)。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Raptor.jpg" target="_blank" rel="noreferrer"><img src="'+_+'" alt="spacex raptor engine"></a></p><p>Raptor 发动机长得跟 Merlin 很像,但有一个关键区别——通过大幅提高压力,SpaceX 让 Raptor 的推力比 Merlin 强了 3 倍多。</p><p>一台 Raptor 发动机能产生 <em>310 吨</em> 推力——足以把 310 吨的东西,也就是 172 辆车叠起来,或者<em>一整架波音 747 客机</em>,推上天。这是<em>一台</em> Raptor 能干的事。<a href="#footnote-3-5715">3</a></p><p>而 BFB 上装了 <em>42 台</em>。<a href="#footnote-4-5715">4</a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/42-Raptors.jpg" target="_blank" rel="noreferrer"><img src="'+y+'" alt="view of 42 Raptor engines"></a></p><p>全部加起来,是前所未闻的 13033 吨推力,足以把 7000 多辆车——或者 <em>50</em> 架大型客机——推上太空。</p><p><strong>大他妈的飞船</strong></p><p>然后是飞船部分——SpaceX 管它叫「行星际飞船 (Interplanetary Spaceship)」,而我打算继续叫它「大他妈的飞船 (Big Fucking Spaceship)」,因为这么叫更好玩。BFS 就是 BFB 顶上那个巨大又酷炫的家伙(如果你已经被搞得大他妈的糊涂了——大他妈的飞船 (BFS) 装在大他妈的助推器 (BFB) 上面,合起来就是我一直叫的大他妈的火箭 (BFR))。BFS 就是把人和货物送去火星的那个东西。它同样也是那个能从火星自己发射升空、把想回家的人带回地球的东西。</p><p>BFS 本身有一栋 16 层高楼那么大,最粗的地方宽 55 英尺。除了几百吨、最终可达 1000 吨的货物之外,BFS 一开始就能载多达 100 人,而且埃隆相信这个数字随时间可以增长到 200 甚至 300 以上——就像一艘游轮。</p><p>装着 9 台 Raptor 发动机,它光是自己的起飞推力就已经超过今天所有的火箭——包括明年就要发射的 Falcon Heavy。作为一个第二级的载货飞船,推力居然比最强的第一级火箭还大,这简直离谱。</p><p>来看看内部剖面:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/rocket-cross-section.jpg" target="_blank" rel="noreferrer"><img src="'+d+'" alt="cross section of spacex mars spacecraft"></a></p><p>我问 Elon,坐在里面是什么感觉。他说:「呃,你会待在一艘巨大的宇宙飞船里,处于微重力状态。<a href="#footnote-5-5715">5</a>我是说,那会挺好玩的。你能到处飘。」</p><p>有道理。</p><p>在发布会问答环节,他补充道:「它必须真的好玩、令人兴奋,不能让人觉得憋屈或无聊。乘员舱的设计能让你玩零重力游戏、到处飘,还会有电影、讲堂、船舱、餐厅——这趟旅程会非常有趣。」</p><p>嗯,好的,现在就把我送上那玩意儿。<em>一艘零重力游轮</em>。窗外还是这个景:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Observatory_F_HD_3.1.png" target="_blank" rel="noreferrer"><img src="'+S+'" alt="observatoryfhd3-1"></a></p><p>如果你真去了,整个流程是这样的:</p><p><strong>1) 上船。</strong> BFR 将从佛罗里达州卡纳维拉尔角 (Cape Canaveral) 的 39A 发射台起飞——就是阿波罗宇航员当年出发的那个发射台。之所以选这里,是因为当年建这个发射台的时候他们还不知道会用多大的火箭,所以建得离谱地大。到了发射台,你走上塔架,穿过登舱桥,进入那艘 Big Fucking Spaceship(超大宇宙飞船)。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Air-bridge.jpg" target="_blank" rel="noreferrer"><img src="'+x+'" alt="air-bridge"></a></p><p><strong>2) 起飞。</strong> 你系好安全带,BFR 起飞。几分钟后,第一级 BFB 分离,返回地球。你所在的 BFS 继续上升,进入地球轨道。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29937258946_8345b8ae6e_o.jpg" target="_blank" rel="noreferrer"><img src="'+F+'" alt="299372589468345b8ae6eo"></a></p><p><strong>3) 在轨加注燃料。</strong> 返回地球后,BFB 顶部换上一艘新的 BFS——这一艘装满了推进剂(液氧和甲烷)。<a href="#footnote-6-5715">6</a>它再次起飞,把这艘装满推进剂的飞船送入轨道,与你所在的飞船交会<a href="#footnote-7-5715">7</a>。两艘飞船像两只手牵手的虎鲸一样对接起来,推进剂随之输送过来。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29343821794_9e05bfd6d7_h.jpg" target="_blank" rel="noreferrer"><img src="'+B+'" alt="293438217949e05bfd6d7h"></a></p><p>这个过程会再重复几次,直到你的飞船完全加满燃料。<a href="#footnote-8-5715">8</a>这个流程至关重要,因为 A) 它降低了旅程的成本;B) 它让旅程快得多。人们一直以为去一趟火星要六到九个月,但 BFS 三个月就能到。</p><p><strong>4) 前往火星。</strong> 在微重力环境里享受三个月的欢乐时光,并且对船上其他人产生严重的审美疲劳。<a href="#footnote-9-5715">9</a> 旅途中,飞船靠冷气推进器来调整姿态,由巨大的太阳能电池阵列供电:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29343822854_ec6f4ffad1_h.jpg" target="_blank" rel="noreferrer"><img src="'+E+'" alt="29343822854ec6f4ffad1h"></a></p><p><strong>5) 进入火星大气层。</strong> 该轮到热盾遭大罪了:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29343824424_87236132a0_h.jpg" target="_blank" rel="noreferrer"><img src="'+R+'" alt="2934382442487236132a0h"></a></p><p><strong>6) 降落火星。</strong> 垂直着陆,和第一级在地球上着陆的方式一样。</p><p><strong>7) 在火星上住一阵子,天知道你在干嘛。</strong> 如果是殖民早期,你多半是去干活的,帮忙把最初的产业搭起来。到后期就什么都可能了——搞科研、创业,或者纯粹是来冒险的。</p><p><strong>8) 在火星上制造推进剂。</strong> 这是火星早期必须建立的关键产业之一。推进剂由液氧 (O2) 和甲烷 (CH4) 组成,而这两种东西正好都可以从火星上现成的大量 H2O (冰) 和 CO2 (火星大气的主要成分) 里轻松制取。他们会用这些推进剂给你搭乘过来的那艘飞船加满油,为它返回地球的航程做准备。这样一来,就省下了从地球一路把返程推进剂运过来的巨额成本。</p><p><strong>9) 要么永远留下,要么回地球。</strong> 如果你要回来,就搭上最新一批飞过来的 BFS 中的一艘。</p><p><strong>10) 垂直降落地球。</strong> 就跟你在火星上做的一样。飞船会进行例行维护,准备两年后再飞火星。</p><p><strong>11) 变成那种烦人透顶的家伙,不管聊什么话题都能想办法把话往「我在火星那段日子」上扯。</strong></p><p>任务完成。</p><p>这张有点让人头晕的图总结了整个过程:</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/diagram.png" target="_blank" rel="noreferrer"><img src="'+X+'" alt="diagram"></a></p><p>而这段视频把它总结得非常爽:</p><p>以上就是「大他妈火箭」是怎么回事,以及它整套流程是怎么运作的。<a href="#footnote-10-5715">10</a></p><p>现在来聊聊,这一切最后可能会怎么演变。</p><p><strong>计划</strong></p><p>回到现实。那么我们要怎么从「有这么一款屌炸天的火箭,可能五年后就能发射」走到「我们是一个欣欣向荣的多行星文明,一百万人生活在火星上」这一步?</p><p>一万次飞行。这就是 Elon 估计要把火星人口带到一百万所需要的 BFS 飞行次数。</p><p>为什么是 10000 次?因为大多数航班上至少会有 100 人,而且这个数字会随时间增加——但每次有人去火星,也会有一些人从火星回来。每艘 BFS 的下半部分是一个巨大的货舱。马斯克认为,要让百万人殖民地实现自给自足,我们至少需要向火星运送 1000 万吨货物,如果 SpaceX 能像他们希望的那样,相对快速地把货物运载能力提升到 1000 吨,那么这需要略多于 10000 次飞行才能完成。</p><p>那这 10000 次旅行什么时候开始呢?</p><p>我们来看看火星-地球会合周期日历 (Mars-Earth Synodic calendar) ——它记录地球和火星距离最近的日期(称为「火星冲日 (Mars opposition)」)。地球的轨道比火星小,所以地球绕太阳转得更快——快到每 26 个月,地球就会「套圈」火星一次,两者短暂地并肩而行。这就是地球-火星之间能进行运输的唯一窗口。</p><p>我们目前离火星相当近,因为上一次火星冲日发生在 2016 年 5 月 22 日。所以如果你碰巧和我一样,是那种「哦操,有颗亮得离谱的星星,让我掏出 Sky Guide app 看看那是哪颗行星,然后告诉身边所有人,结果再一次,没人在乎,因为每个人都是可怕的人」的书呆子,你就会知道,整个夏天火星在夜空中都异常显眼、异常明亮。<a href="#footnote-11-5715">11</a> 一年之后,火星将运行到太阳的另一侧,我们在夜空中将完全看不到它。</p><p>2016 年的地球-火星冲日还有一个特殊之处,因为这是最后一次没人谈论它的冲日。</p><p>为什么?因为从 2018 年 7 月的下一次冲日开始,SpaceX 将在每次冲日时都往火星送东西,而且这件事每次都会成为越来越大的新闻。以下是暂定的时间表,如果一切按计划完美进行的话:</p><p><strong>即将到来的火星冲日</strong> ——以及 SpaceX 对每次冲日的规划</p><p><strong>2018 年 7 月:</strong> 派一艘 <a href="http://www.spacex.com/dragon" target="_blank" rel="noreferrer">Dragon</a> 飞船(猎鹰 9 号搭载的 SUV 大小的飞船)带着货物飞往火星</p><p><strong>2020 年 10 月:</strong> 派多艘 Dragon 飞船,带更多货物</p><p><strong>2022 年 12 月:</strong> BFS 首航火星。仅载货。这是马斯克想命名为「黄金之心 (Heart of Gold)」的那艘飞船。</p><p><strong>2025 年 1 月:</strong> 首次载人 BFS 飞往火星。</p><p>我们都回过头再读一遍最后那行。</p><p><em><strong>2025 年 1 月:</strong> 首次载人 BFS 飞往火星。</em></p><p>你注意到了吗?</p><p>如果一切按计划进行,<em>火星版的尼尔·阿姆斯特朗将在大约八年后着陆。</em></p><p>而现在几乎没人在谈论这件事。</p><p>但他们会谈的。炒作会在几年后 Dragon 飞船前往火星时开始,而在 2022 年,当那艘牛逼哄哄的大飞船 (Big Fucking Spaceship) 终于发射、飞往火星并降落时,炒作将进入高潮。每个人都会在谈论这件事。</p><p>从那时起,热度只会不断升温——第一批 BFS 宇航员的名单会被公布,他们会成为家喻户晓的名字,因为他们的勇气而受人敬仰,毕竟所有人都知道,任务出岔子、他们回不来的可能性是切实存在的。然后,在 2024 年,他们将踏上为期三个月的旅程,每一天都是头版头条。他们着陆的那一刻,地球上的每一个人都会屏息观看。这将是 1969 年的重演。</p><p>这是真的会发生的事。</p><p>马斯克不喜欢别人问他这次首航,以及问「谁会成为火星上的尼尔·阿姆斯特朗」。他说这不是要让人类在多行星文明的帽子上再插一根羽毛,而且他会立刻指出:「把人送上月球超级令人兴奋——可我们的月球基地在哪儿?」换句话说,让人类跟火星击个掌来炫耀,并不是重点——重点是把完整的愿景落地,真正在火星上建立一个完全自给自足的文明。</p><p>嗯,好吧,行行行。但<em>我就是很期待 2025 年</em>。那会超级好玩。</p><p>总之,下一次火星冲将在 2027 年到来。这一次,如果一切顺利,多艘 BFS 将同时前往火星,搭载的人比 2025 年的首批人数还要多。而那艘 2025 年飞过去的飞船——那艘太空版「五月花号」——将踏上返回地球的旅程,把首批火星拓荒者中的一些人带回家。他们将作为国际英雄凯旋,受到盛大的欢迎,而那艘传奇飞船则会光荣退役,进入航空航天博物馆安享晚年。</p><p>与此同时,我们所有人都会紧盯着电视<a href="#footnote-12-5715">12</a>,看这一批 BFS 抵达火星,船上的人将接续 2025 年那批人开启的艰苦工作。早期殖民者的日子会很难过,一如所有历史上的早期殖民者那样——而这一次会格外艰难。他们不仅要真真切切地从零开始——挖矿井、开采石场、建冶炼厂,建造第一座地下村落栖息地以及火星上第一批医院、学校、温室农场,铺设庞大的管道系统把水抽进村子,建造第一座火箭燃料工厂——而且这一切都必须在这样一个地方完成:不穿宇航服就不能出门,他们此生所认识的每一个人和每一样东西,都在夜空中那颗淡蓝色的小点上。</p><p>会很难,但对我们这个世界的探险者来说,回报也许是值得的。马斯克说:「你在 24 小时内可以到达地球上的任何地方。地球上已经没有物理意义上的前沿了。而现在,太空就是那个前沿,所以它会吸引所有拥有探索精神的人。」</p><p>2029 年 4 月,SpaceX 将向火星派出更大规模的一批飞船、人员和货物。这一次,受到的关注可能反而会少一些。到 2029 年,我们可能已经习惯了「火星上有人」这件事,以及每 26 个月就会发生一次盛大的双向迁徙。</p><p>不断扩张的火星殖民地将继续吸引冒险者——那些读到 15、16 世纪伟大航海壮举、渴望身临其境的人。当我问 Elon 这个小殖民地将如何成长和演变时,他说:&quot;把火星殖民地想象成一个生物体,从受精卵开始,然后变成多细胞,再然后出现器官分化——所以它不会一路上都长一个样,就像最初的詹姆斯敦 (Jamestown) 定居点也代表不了今天的美国。火星也一样——火星将成为新的新世界。&quot;</p><p>2031、2033 和 2035 年的冲日将把更多的人带到这个新的新世界。到那时,这座萌芽中的火星城市将成为我们生活的一部分。我们会关注一些我们最喜欢的火星记者的推特,追踪那里正在发生的事。我们都会迷上火星第一批爆款真人秀。而我们中的一些人会开始琢磨:&quot;要不要趁还没老,哪年报个名去火星?&quot;</p><p>到 2050 年,火星上会有超过十万人。你儿子工作的公司可能在那里设了分部,他正要跟几位即将前往火星驻扎 52 个月的同事道别。他告诉你他不想去,因为不想把上九年级的女儿从她的生活和朋友身边带走。但他说她正在申请一个项目,会让她 17 到 23 岁期间去火星读城市规划学位。你有些担心,尽管你知道这不理性。只是你还记得去火星是有风险、有危险的那些日子,你内心的某个角落还是对此感到不安。而且万一她决定不回来呢?</p><p>到 2065 年,火星早期的日子看起来已经很原始了。最初几次火星移民时,每次只有几艘飞船,每艘只载 100 人,票价贵得离谱,飞过去要三个月,而且火星上只有那么几个非常艰苦的行业可以打工。</p><p>到 2065 年,每次火星冲日都有超过 1000 艘飞船启程,每艘搭载 500 多人和几千吨货物。每两年就有 50 万人踏上旅程,回来的比这少大约 5 万人,因为随着新飞船不断建造,地火移民运力每次都会略有增长。这趟旅程现在只需 30 天,票价只要 6 万美元(以 2016 年美元计)——而大多数人只需用他们在火星上的高薪工作就能还清票价(随着早期火星城市持续扩张、新城市不断建成,劳动力需求极高)。</p><p>很多人还记得火星殖民的早期岁月,那时一切都是 SpaceX 一手操办的——资金来自 SpaceX 或它的货运客户,推动力是他们的野心、他们的智慧和他们的胆量。但如今,已经有几十家公司专门搞地球-火星运输,几百家公司在火星上做开发和创业。而运输的付费方式就像今天的飞机、火车和大巴一样——乘客买票。</p><h2 id="十年之后-2074-年的这次移民让火星人口突破了一百万。两个星球上都爆发了小规模的庆祝活动-一个期盼已久的里程碑终于达成。不过-大多数人甚至都没注意到。" tabindex="-1">十年之后,2074 年的这次移民让火星人口突破了一百万。两个星球上都爆发了小规模的庆祝活动,一个期盼已久的里程碑终于达成。不过,大多数人甚至都没注意到。 <a class="header-anchor" href="#十年之后-2074-年的这次移民让火星人口突破了一百万。两个星球上都爆发了小规模的庆祝活动-一个期盼已久的里程碑终于达成。不过-大多数人甚至都没注意到。" aria-label="Permalink to &quot;十年之后,2074 年的这次移民让火星人口突破了一百万。两个星球上都爆发了小规模的庆祝活动,一个期盼已久的里程碑终于达成。不过,大多数人甚至都没注意到。&quot;">​</a></h2><p>我刚才说的这一切,都是基于 Elon 在电话里跟我讲的东西。有些是他直接说出的数字——比如上面那段,来自他说的一句话:「我希望我们能在起步大约 50 年之后达到一百万人。」还有些是我根据他给我的预测所推演出来的可能的未来。这一切都是有现实依据的。至少,是基于 Elon Musk 对现实的最佳推测。他非常谨慎,凡是听起来像预测或推断的话,都要加上限定语:「<em>如果</em>一切顺利,这就是<em>可能</em>发生的情况——但没法确定,一路上很多事都可能出岔子。」他强调:「并不是说 SpaceX 有全部答案,我们已经搞定了一切什么的——而是我们想证明这事儿是可能的。但绝不是板上钉钉。」至于可能出错的事,他列举了几样(比如第三次世界大战),而他最大的担忧之一是:万一自己英年早逝,SpaceX 可能会被某个想榨干公司牟利的人接手,而不是一门心思聚焦在火星文明这个使命上。</p><p>但如果 SpaceX 真能把这件事启动起来,Elon 认为这本身不仅是件大事,还可能引爆人类的一大堆新可能性。他解释道:</p><p><em>大局不只是给硬盘做个备份,而是真正把人类变成一个跨行星物种。本质上我们说的是:我们正在建立一条通往火星的常规货运路线。有了行星际商业这个经济上的推动函数,就会有资源和动力去大规模改进太空运输技术,我觉得那时候事情就会真正上升到一个全新的层次。</em></p><p><em>我描述的这些听起来可能真的很疯狂,但只要我们成为一个双行星文明,这其实只是最终会完成的事情中的一小部分而已。看看欧洲的航运技术。当你只需要横穿地中海时,船只都挺烂的——它们过不了大西洋。所以商业基本上只有短程船只。没有一个倒逼的动力,航运技术就没什么大的进步——凯撒大帝那个年代的船,和哥伦布那个年代的船,能干的事儿基本差不多。1500 年过去了,你还是只能横穿地中海。但是一旦有了横渡大西洋的理由,航运技术就飞速改进。要让这事儿发生,得先有美洲殖民地这个动机。</em></p><p>SpaceX 的人相信,一旦我们登上火星,太阳系的其余部分也会随之变得触手可及。这就是为什么他们不只是画了张「牛逼大火箭」骄傲地立在火星上的图,而是把它画成了飞掠木星的样子。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29343909374_f5a0c62478_h.jpg" target="_blank" rel="noreferrer"><img src="'+j+'" alt="29343909374f5a0c62478h"></a></p><p>还有土星。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29343908684_4caef4cd2c_h.jpg" target="_blank" rel="noreferrer"><img src="'+T+'" alt="293439086844caef4cd2ch"></a></p><p>以及把人类探险家带到遥远的卫星上。</p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29343905184_aa6202b3a4_k.jpg" target="_blank" rel="noreferrer"><img src="'+q+'" alt="29343905184aa6202b3a4k"></a></p><p><a href="https://waitbutwhy.com/wp-content/uploads/2016/09/29343906874_abb7572f12_k.jpg" target="_blank" rel="noreferrer"><img src="'+C+'" alt="29343906874abb7572f12k"></a></p><p>他们规划的是这样一个时代:任何人都可以去我们这个浩瀚太阳系里的任何地方——一个探索的新黄金时代,每个方向都有尚未被涉足的物理疆界。</p><h2 id="" tabindex="-1"><a href="https://gum.co/wbw-bfr" target="_blank" rel="noreferrer"><img src="'+M+'" alt="Buy the PDF"></a> <a class="header-anchor" href="#" aria-label="Permalink to &quot;[![Buy the PDF](/images/spacexs-big-fking-rocket-the-full-story/PDF-Button.png)](https://gum.co/wbw-bfr)&quot;">​</a></h2><p>如果你喜欢 Wait But Why,请订阅我们的 <strong><a href="https://newsletter.waitbutwhy.com/join" target="_blank" rel="noreferrer">邮件列表</a></strong>,新文章发布时我们会发送给你。</p><h2 id="要支持-wait-but-why-请访问我们的-patreon-页面。" tabindex="-1">要支持 Wait But Why,请访问我们的 <strong><a href="https://patreon.com/waitbutwhy" target="_blank" rel="noreferrer">Patreon 页面</a></strong>。 <a class="header-anchor" href="#要支持-wait-but-why-请访问我们的-patreon-页面。" aria-label="Permalink to &quot;要支持 Wait But Why,请访问我们的 **[Patreon 页面](https://patreon.com/waitbutwhy)**。&quot;">​</a></h2><p>以下是 WBW 埃隆·马斯克 (Elon Musk) 系列的完整目录:</p><p><strong>第 1 部分,关于 Elon:<a href="https://waitbutwhy.com/2015/05/elon-musk-introduction.html" target="_blank" rel="noreferrer">Elon Musk 系列:引言</a><a href="https://waitbutwhy.com/2015/05/elon-musk-the-worlds-raddest-man.html" target="_blank" rel="noreferrer"><br></a>第 2 部分,关于 Tesla:<a href="https://waitbutwhy.com/2015/06/how-tesla-will-change-your-life.html" target="_blank" rel="noreferrer">Tesla 将如何改变世界</a></strong><br><strong>第 3 部分,关于 SpaceX:<a href="https://waitbutwhy.com/2015/08/how-and-why-spacex-will-colonize-mars.html" target="_blank" rel="noreferrer">SpaceX 将如何(以及为何)殖民火星<br></a>第 4 部分,关于让 Elon 如此高效的秘诀:<a href="https://waitbutwhy.com/2015/11/the-cook-and-the-chef-musks-secret-sauce.html" target="_blank" rel="noreferrer">厨师与烹调工:Musk 的独门秘方</a></strong></p><p>额外文章 #1:<a href="https://waitbutwhy.com/2015/06/the-deal-with-solar.html" target="_blank" rel="noreferrer">关于 Solar City 那点事</a><br> 额外文章 #2:<a href="https://waitbutwhy.com/2015/06/hyperloop.html" target="_blank" rel="noreferrer">关于 Hyperloop 那点事</a></p><p>另外六篇 Wait But Why 长文科普:</p><p><strong><a href="https://waitbutwhy.com/2014/02/american-presidents-washington-lincoln.html" target="_blank" rel="noreferrer">美国总统们——从华盛顿到林肯</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/09/muhammad-isis-iraqs-full-story.html" target="_blank" rel="noreferrer">从穆罕默德到 ISIS:伊拉克的完整故事</a></strong></p><p><strong><a href="https://waitbutwhy.com/2015/01/artificial-intelligence-revolution-1.html" target="_blank" rel="noreferrer">AI 革命:通往超级智能之路</a></strong></p><p><strong><a href="https://waitbutwhy.com/2014/05/fermi-paradox.html" target="_blank" rel="noreferrer">费米悖论 (Fermi Paradox):外星人都跑哪儿去了?</a></strong></p><p><strong><a href="https://waitbutwhy.com/2016/03/cryonics.html" target="_blank" rel="noreferrer">人体冷冻是怎么回事(以及为什么它讲得通)</a></strong></p><p><strong><a href="https://waitbutwhy.com/2013/12/how-to-name-baby.html" target="_blank" rel="noreferrer">怎么给宝宝起名</a></strong></p><hr><ol><li><p>这是《银河系漫游指南》(<em>Hitchhiker&#39;s Guide to the Galaxy</em>) 里的梗。书里,黄金之心号是「第一艘利用无限不可能性驱动的宇宙飞船」。Elon 喜欢这个名字,因为他觉得 SpaceX 走过的路极度不可能。<a href="#note-1-5715">↩</a></p></li><li><p>澄清一下,<em>载荷 (payload)</em> 是火箭实际能带上太空的东西。<em>推力 (thrust)</em> 是发动机能<em>推</em>上太空的东西,必须包括整个 BFR 加上里面装的载荷。火箭的推力几乎全部用来抬升火箭本身,只有一小部分分给载荷。我在这几篇文章里谈到推力、说某组发动机能把多少辆车推上太空时,我说的是一个假想场景——没有火箭,只有火箭的发动机,上面架一个平台,平台上再堆满车。<a href="#note-2-5715">↩</a></p></li><li><p>这是猛禽 (Raptor) 首次试车的<a href="https://www.youtube.com/watch?v=e7kqFt3nID4" target="_blank" rel="noreferrer">视频</a>,几天前的事。把手伸进那道火柱里肯定超级不好玩。<a href="#note-3-5715">↩</a></p></li><li><p>我问 Elon 为什么用 42 台小一点的发动机,而不是数量更少的巨型发动机,他说他们一度考虑过更大的发动机,但「优化的结果似乎是更多小发动机,而不是更少大发动机」。我没法再解释了,因为我也没懂。<a href="#note-4-5715">↩</a></p></li><li><p>我们常常以为飘着的宇航员处于「零重力」中。其实他们飘着的时候完全还在地球的引力井里——只不过他们绕地球转得太快,处于持续的自由落体状态。效果是一样的——他们飘着——但既然不是真的零重力,我们就叫它微重力。<a href="#note-5-5715">↩</a></p></li><li><p>用甲烷这一点是重大创新。其他火箭,包括猎鹰,主燃料用的是煤油——但出于一系列<a href="https://waitbutwhy.com/wp-content/uploads/2016/09/Methane-1.jpg" target="_blank" rel="noreferrer">原因</a>,甲烷对火星之旅似乎更合适。<a href="#note-6-5715">↩</a></p></li><li><p>拼写让人看着不爽的一个词。<a href="#note-7-5715">↩</a></p></li><li><p>Elon 说,如果补加燃料的过程很快,比如几周以内,那就按这个计划来。如果时间长得多,那飞船会先无人发射,等它加满燃料准备就绪后,再单独发射一艘只载人的飞船,在地球轨道会合,把机组人员送上去。<a href="#note-8-5715">↩</a></p></li><li><p>人们喜欢提这段时间里太空辐射的危险。Elon 觉得这被夸大了,加上适当的防护措施(比如船员舱周围一层水做屏蔽),辐射对机组成员身体的伤害,大概相当于在那三个月里变成一个烟民、然后戒掉——不理想,但也没啥大不了。<a href="#note-9-5715">↩</a></p></li><li><p>在发布会上,Elon 一度跑题,让我特别开心。他讲到 BFR 的飞船有可能兼职做地球上超高速运输人和货物的工具:「它其实能力足够,你甚至可以让这艘飞船进入轨道……也许全世界范围内超快速运输货物是有市场的……我们可以在最多 45 分钟内把货物运到地球上任何地方——大多数可能就 20、25 分钟。所以也许在纽约海岸外弄个漂浮平台,你就能 25 分钟从纽约到东京。跨大西洋 10 分钟。大部分时间花在去平台的路上,之后就非常快了。这里面有一些很吸引人的可能性,但我们没打算靠这个。」爽。这真是对未来世界的美妙一瞥——某人从德里给你发短信问你要不要从旧金山飞过来一起吃午饭,你说「行啊,不过我两小时后有个会,不能待太久」。当然你不会这么做,因为你会直接和朋友虚拟见面,感觉就跟本人到场一模一样。所以这事也就黄了。<a href="#note-10-5715">↩</a></p></li><li><p>整个夏天火星旁边一直有一颗挺亮的土星——这事我也跟一堆不关心的人念叨过。<a href="#note-11-5715">↩</a></p></li><li><p>或者 2027 年的人类被什么黏着不放,就是那个东西。<a href="#note-12-5715">↩</a></p></li></ol><hr><ol><li>所有图片均来自 spacex.com,除非底部标注了 &quot;waitbutwhy.com&quot;,那些是我自己做的。<a href="#note2-1-5715">↩</a></li></ol><p><a href="https://twitter.com/share" target="_blank" rel="noreferrer">Tweet</a></p><p><a href="//www.pinterest.com/pin/create/button/?url=https://waitbutwhy.com/2016/09/spacexs-big-fking-rocket-the-full-story.html&amp;description=SpaceX%E2%80%99s%20Big%20Fucking%20Rocket%20%E2%80%93%20The%20Full%20Story" target="_blank" rel="noreferrer"><img src="'+v+'" alt=""></a></p>',210)])])}const O=r(P,[["render",I]]);export{G as __pageData,O as default};
